实现如下：

def find_pairs(lst, target):
    mapping = {}
    for index, num in enumerate(lst):
        mapping[num] = index

    result = []
    for index, num in enumerate(lst):
        if num + target in mapping:
            result.append((index, mapping[num+target]))
    return result

